[1]: https://github.com/GoogleCloudPlatform/gcloud-python/pull/1629#discussion_r56703095

This `numpyleak` module leaks memory when passing a `numpy.array` to the `leak` function, observe with e.g. `watch -n .2 "ps aux | sed -n '1p;/[n]umpyleak.py/p'"`. Tested on various 64bit Linux systems with python 3.5 and 3.6.

```
#include <pybind11/pybind11.h>
#include <pybind11/numpy.h>
#include <pybind11/stl.h>

namespace py = pybind11;

using leaking_uint = const std::vector<unsigned>&;
using ok_signed_int = const std::vector<int>&;

PYBIND11_MODULE(numpyleak, m) {
    m.def("leak", [](leaking_uint i) {
       return i.back() + i.front();
    });
    m.def("ok", [](const py::array_t<unsigned>& i) {
       return i.at(0) + i.at(i.size()-1);
    });
    m.def("noleak", [](ok_signed_int i) {
       return i.back() + i.front();
    });
}
```

```
#!/usr/bin/env python3

import numpy as np
from numpyleak import leak, noleak, ok

def loop(n, fn):
    # dtype.uint makes no difference
    X = np.random.randint(1000, size=40, dtype=np.int)

    i = 0
    while True:
        a = fn(X) # !
        if i % 500 == 0:
            print(i//5000, a)
        if i > n:
            break
        else:
            i += 1

loop(40100, leak)
input('memory not freed ')
loop(40100, leak)
input('done leaking ')

loop(202100, ok)
loop(202100, ok)
input('array_t done ')

loop(80200, noleak)
input('done ')
print('no double free on exit')
```
